@namespace sv_9a962f5712bb4a09ace12aa3fdbe1997.Components.Pages.JobApplication

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between m-0 p-0">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var step = i + 1;
            var state = step == CurrentStep ? "active"
                      : CompletedSteps.Contains(step) ? "completed"
                      : "future";
            <li class="step-item @state" @onclick="() => OnStepClick(step)" role="button">
                <div class="step-circle">
                    @if (state == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <span class="step-label">@StepLabels[i]</span>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepLabels =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

nav.step-indicator ol {
    counter-reset: step;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    text-align: center;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 20px);
    width: calc(100% - 40px);
    height: 2px;
    background-color: #dee2e6;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    position: relative;
    z-index: 1;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
    cursor: pointer;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.8rem;
    color: #adb5bd;
    white-space: nowrap;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

@namespace sv_9a962f5712bb4a09ace12aa3fdbe1997.Components.Pages.JobApplication

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-start mb-2">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>
        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company <span class="text-danger">*</span></label>
                <input class="form-control @ValidationClass(Entry.Company)" @bind="Entry.Company" />
                @if (ShowErrors && string.IsNullOrWhiteSpace(Entry.Company))
                {
                    <div class="invalid-feedback d-block">Company name is required.</div>
                }
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control @ValidationClass(Entry.Title)" @bind="Entry.Title" />
                @if (ShowErrors && string.IsNullOrWhiteSpace(Entry.Title))
                {
                    <div class="invalid-feedback d-block">Job title is required.</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control @(ShowErrors && Entry.StartDate is null ? "is-invalid" : "")"
                       @bind="Entry.StartDate" />
                @if (ShowErrors && Entry.StartDate is null)
                {
                    <div class="invalid-feedback d-block">Start date is required.</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" @bind="Entry.IsCurrent"
                           id="@($"current-{Index}")" />
                    <label class="form-check-label" for="@($"current-{Index}")">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" @bind="Entry.Description"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public bool ShowErrors { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private string ValidationClass(string value) =>
        ShowErrors && string.IsNullOrWhiteSpace(value) ? "is-invalid" : "";
}

