nav.step-indicator ol {
    counter-reset: step;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    text-align: center;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 20px);
    width: calc(100% - 40px);
    height: 2px;
    background-color: #dee2e6;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    position: relative;
    z-index: 1;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
    cursor: pointer;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.8rem;
    color: #adb5bd;
    white-space: nowrap;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

