@namespace sv_9a962f5712bb4a09ace12aa3fdbe1997.Components.Pages.JobApplication

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between m-0 p-0">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var step = i + 1;
            var state = step == CurrentStep ? "active"
                      : CompletedSteps.Contains(step) ? "completed"
                      : "future";
            <li class="step-item @state" @onclick="() => OnStepClick(step)" role="button">
                <div class="step-circle">
                    @if (state == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <span class="step-label">@StepLabels[i]</span>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepLabels =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

