<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(emailError))
{
    <div class="alert alert-danger">@emailError</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control @ValidationClass(Model.FullName)" @bind="Model.FullName" />
        @if (showErrors && string.IsNullOrWhiteSpace(Model.FullName))
        {
            <div class="invalid-feedback d-block">Full name is required.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @ValidationClass(Model.Email)" @bind="Model.Email" />
        @if (showErrors && string.IsNullOrWhiteSpace(Model.Email))
        {
            <div class="invalid-feedback d-block">Email is required.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input class="form-control @ValidationClass(Model.Phone)" @bind="Model.Phone" />
        @if (showErrors && string.IsNullOrWhiteSpace(Model.Phone))
        {
            <div class="invalid-feedback d-block">Phone number is required.</div>
        }
    </div>
