@namespace sv_9a962f5712bb4a09ace12aa3fdbe1997.Components.Pages.JobApplication

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="10" maxlength="@MaxLength"
              @bind="CoverLetter" @bind:event="oninput"
              @bind:after="NotifyChanged"></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private async Task NotifyChanged() => await CoverLetterChanged.InvokeAsync(CoverLetter);
}

@namespace sv_9a962f5712bb4a09ace12aa3fdbe1997.Components.Pages.JobApplication
@using sv_9a962f5712bb4a09ace12aa3fdbe1997.Models

<h4 class="mb-3">Review Your Application</h4>

@if (Submitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-2">&#10003; Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="#" @onclick="() => OnEditSection.InvokeAsync(1)" @onclick:preventDefault class="text-primary">Edit</a>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <a href="#" @onclick="() => OnEditSection.InvokeAsync(2)" @onclick:preventDefault class="text-primary">Edit</a>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="#" @onclick="() => OnEditSection.InvokeAsync(3)" @onclick:preventDefault class="text-primary">Edit</a>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <a href="#" @onclick="() => OnEditSection.InvokeAsync(4)" @onclick:preventDefault class="text-primary">Edit</a>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@(string.IsNullOrWhiteSpace(CoverLetter) ? "(none)" : CoverLetter)</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool Submitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }
    [Parameter] public string? ErrorMessage { get; set; }
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}

