@page "/apply"
@namespace sv_9a962f5712bb4a09ace12aa3fdbe1997.Components.Pages.JobApplication
@rendermode InteractiveServer
@using sv_9a962f5712bb4a09ace12aa3fdbe1997.Models

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 820px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo"
                                  OnNext="() => AdvanceTo(2)" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="() => AdvanceTo(3)"
                                 OnBack="() => GoToStep(1)" />
                break;
            case 3:
                <ReferencesStep References="references"
                                OnNext="() => AdvanceTo(4)"
                                OnBack="() => GoToStep(2)" />
                break;
            case 4:
                <CoverLetterStep @bind-CoverLetter="coverLetter"
                                 OnNext="() => AdvanceTo(5)"
                                 OnBack="() => GoToStep(3)" />
                break;
            case 5:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            IsSubmitting="isSubmitting"
                            Submitted="submitted"
                            ApplicationId="applicationId"
                            ErrorMessage="errorMessage"
                            OnEditSection="GoToStep"
                            OnSubmit="SubmitApplication"
                            OnBack="() => GoToStep(4)" />
                break;
        }
    </div>
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep = 1;
    private readonly HashSet<int> completedSteps = [];

    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = [new()];
    private readonly List<ReferenceModel> references = [new()];
    private string coverLetter = "";

    private bool isSubmitting;
    private bool submitted;
    private int? applicationId;
    private string? errorMessage;

    private void AdvanceTo(int step)
    {
        completedSteps.Add(currentStep);
        currentStep = step;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
                new WorkHistory(workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate!.Value, e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
                references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            submitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

